import re
import xml.etree.ElementTree as ET

def parse_xml_or_fallback(raw: str, tags: list[str]) -> dict:
    # Attempt proper XML parse
    try:
        root = ET.fromstring(f"<root>{raw}</root>")
        return {t: (root.findtext(t) or "").strip() for t in tags}
    except ET.ParseError:
        # Fall back to lenient regex extraction
        result = {}
        for tag in tags:
            m = re.search(rf"<{tag}>(.*?)</{tag}>", raw, re.DOTALL)
            result[tag] = m.group(1).strip() if m else None
        return result

import re

# Compile once at module level
_PATTERNS = {
    tag: re.compile(rf"<{tag}>(.*?)</{tag}>", re.DOTALL)
    for tag in ["thinking", "answer", "confidence", "risk-flags"]
}

def fast_extract(text: str, tag: str) -> str | None:
    m = _PATTERNS[tag].search(text)
    return m.group(1).strip() if m else None

import xml.etree.ElementTree as ET

def parse_well_formed(raw: str) -> dict:
    root = ET.fromstring(f"<root>{raw}</root>")
    return {
        "thinking": (root.findtext("thinking") or "").strip(),
        "answer":   (root.findtext("answer")   or "").strip(),
    }

from lxml import etree

parser = etree.XMLParser(
    resolve_entities=False,  # Disable XXE
    no_network=True,         # Block network fetches
    load_dtd=False,          # Do not load DTDs
)

def safe_lxml_parse(raw: str) -> etree._Element:
    xml_bytes = f"<root>{raw}</root>".encode()
    return etree.fromstring(xml_bytes, parser=parser)
